export interface Track {
  id: string;
  name: string;
  description: string;
  role: string;
  moduleCount: number;
  completedModules: number;
  clearanceStatus: "pending" | "in-progress" | "cleared" | "restricted";
}

export interface Module {
  id: string;
  trackId: string;
  title: string;
  category: string;
  description: string;
  stepCount: number;
  completedSteps: number;
  status: "locked" | "available" | "in-progress" | "completed";
}

export interface Step {
  id: string;
  moduleId: string;
  title: string;
  content: string;
  contentType: "text" | "quiz" | "interactive";
  durationMinutes: number;
  completed: boolean;
}

export interface QuizQuestion {
  id: string;
  question: string;
  options: string[];
  correctIndex: number;
  explanation: string;
}

export interface QuizResult {
  moduleId: string;
  score: number;
  totalQuestions: number;
  passed: boolean;
  answers: { questionId: string; selectedIndex: number; correct: boolean }[];
}

export interface Employee {
  id: string;
  name: string;
  employeeId: string;
  track: string;
  startDate: string;
  clearanceStatus: "pending" | "in-progress" | "cleared" | "restricted";
  supervisor: string;
  completedModules: number;
  totalModules: number;
}

export interface Evidence {
  id: string;
  title: string;
  moduleTitle: string;
  submittedAt: string;
  status: "pending" | "reviewing" | "approved" | "rejected";
  fileName: string;
  fileSize: string;
  fileContent?: string;
  fileType?: string;
}

export interface UploadedFile {
  id: string;
  name: string;
  size: number;
  type: string;
  content: string;
  uploadedAt: string;
}

