  "mod-100": [
    { id: "q397", question: "What does dignity mean in your role as a direct care staff?", options: ["Making decisions for youth", "Treating youth with respect and honoring their worth", "Giving privileges to earn trust", "Avoiding difficult conversations"], correctIndex: 1, explanation: "The correct answer is: Treating youth with respect and honoring their worth. Dignity means recognizing the inherent worth of every youth and treating them with respect, regardless of circumstances." },
    { id: "q398", question: "True or False: Treating youth with respect means listening to their perspective, even if you disagree.", options: ["True", "False"], correctIndex: 0, explanation: "The correct answer is: True. Respectful treatment includes active listening and validating youth perspectives, even when you hold a different view." },
    { id: "q399", question: "What is the primary purpose of supervision?", options: ["To evaluate staff only", "To ensure youth safety, support quality care, and guide professional growth", "To correct mistakes after they happen", "To complete paperwork"], correctIndex: 1, explanation: "The correct answer is: To ensure youth safety, support quality care, and guide professional growth. Supervision serves multiple purposes centered on safety and quality." },
    { id: "q400", question: "Which of the following is an appropriate professional boundary?", options: ["Sharing personal social media with youth", "Giving gifts or money", "Maintaining a professional relationship focused on youth needs", "Meeting with youth one-on-one off-site"], correctIndex: 2, explanation: "The correct answer is: Maintaining a professional relationship focused on youth needs. Professional boundaries keep relationships centered on the youth's needs, not the staff member's." },
    { id: "q401", question: "A youth discloses abuse or harm to themselves or others. What should you do first?", options: ["Keep it confidential", "Investigate the details", "Report it immediately to your supervisor", "Tell other staff before your supervisor"], correctIndex: 2, explanation: "The correct answer is: Report it immediately to your supervisor. Mandated reporting requires immediate notification to supervisors and proper authorities." },
    { id: "q402", question: "True or False: Documentation should be objective, factual, and free of opinions.", options: ["True", "False"], correctIndex: 0, explanation: "The correct answer is: True. Documentation must be objective and factual. Record what you observed, not what you interpreted or assumed." },
    { id: "q403", question: "Two youth are arguing loudly in the common area. What is the best first response?", options: ["Yell to get their attention", "Calmly approach and separate the youth", "Ignore it and let them resolve it", "Send both youth to timeout immediately"], correctIndex: 1, explanation: "The correct answer is: Calmly approach and separate the youth. Calm, early intervention models respect and helps youth build conflict resolution skills." },
    { id: "q404", question: "A youth asks you to keep a secret about wanting to spend time alone outside program hours. What should you do?", options: ["Agree to keep the secret to build trust", "Clearly state program rules and professional boundaries", "Give them your personal phone number to talk later", "Promise not to tell anyone"], correctIndex: 1, explanation: "The correct answer is: Clearly state program rules and professional boundaries. Secrets and private contact violate professional boundaries and program rules." },
    { id: "q405", question: "Which of the following is a RED FLAG that may indicate a boundary concern?", options: ["Youth participating actively in group activities", "Staff showing favoritism or over-involvement with a specific youth", "Youth completing their daily tasks on time", "Staff documenting incidents promptly"], correctIndex: 1, explanation: "The correct answer is: Staff showing favoritism or over-involvement with a specific youth. Red flags include favoritism, youth isolating, unexplained injuries, boundary crossing, and youth hinting at harm." },
    { id: "q406", question: "What is the correct order of the 5-Step Supervision Response Model?", options: ["Observe, Engage, Protect, Report, Escalate", "Report, Observe, Engage, Protect, Escalate", "Engage, Observe, Protect, Report, Escalate", "Observe, Protect, Engage, Report, Escalate"], correctIndex: 0, explanation: "The correct answer is: Observe, Engage, Protect, Report, Escalate. First notice what's happening, then connect, ensure safety, document, and get additional support if needed." },
  ],
