// ─── Helper Functions ───────────────────────────────────────

export function getProgressPercentage(completed: number, total: number): number {
  return total === 0 ? 0 : Math.round((completed / total) * 100);
}

export function getModulesByTrack(trackId: string): Module[] {
  return modules.filter((m) => m.trackId === trackId);
}

export function getModuleById(id: string): Module | undefined {
  return modules.find((m) => m.id === id);
}

export function getStepsByModule(moduleId: string): Step[] {
  return steps.filter((s) => s.moduleId === moduleId);
}

export function getQuizForModule(moduleId: string): QuizQuestion[] {
  return quizData[moduleId] || [];
}

export function hasQuiz(moduleId: string): boolean {
  return (quizData[moduleId]?.length || 0) > 0;
}

export function getEmployeeById(id: string): Employee | undefined {
  return employees.find((e) => e.id === id);
}

export function getTrackById(id: string): Track | undefined {
  return tracks.find((t) => t.id === id);
}

export function getEvidenceByModule(moduleTitle: string): Evidence[] {
  return evidenceList.filter((e) => e.moduleTitle === moduleTitle);
}
